sql:
SELECT AVG(max_speed) AS average_max_speed
FROM (
    SELECT trip_id, MAX(speed) AS max_speed
    FROM trip_logs
    GROUP BY trip_id
);

external_knowledge:
- "completed trips" refer to trips that were successfully finished without cancellation;
- "safety records" include the number of safety incidents reported for each driver;
- "maintenance costs" are the average costs of maintaining vehicles for each company.

sql:
SELECT COUNT(trip_id) 
FROM trips 
WHERE trip_status = 'completed' AND trip_fare > (SELECT AVG(trip_fare) FROM trips);

